            await comp.SetParametersAndRenderAsync(parameters => parameters.Add(x => x.MultiSelection, true));
            comp.Render();
            await comp.Instance.SetSelectedItemAsync(4);

            // two way binding should have updated
            selectedItems.Should().Contain(4);
